// Map LinkedIn (Apify) results to GIMS Lead interface
const webhookData = $('Webhook Trigger').first().json;
const results = $input.all().map(i => i.json);
const leadSourceId = webhookData.lead_source_id || null;
const limit = webhookData.limit || 10;

const leads = results.slice(0, limit).map(person => {
  const firstName = person.firstName || person.first_name || (person.fullName || 'Unknown').split(' ')[0] || 'Unknown';
  const lastName = person.lastName || person.last_name || (person.fullName || '').split(' ').slice(1).join(' ') || '';

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: person.companyName || person.company || '',
    email: person.email || '',
    phone: person.phone || person.phoneNumber || '',
    job_title: person.title || person.headline || person.position || '',
    address: person.location || person.address || '',
    city: webhookData.city || (person.location || '').split(',')[0]?.trim() || '',
    province: (person.location || '').split(',').slice(1).join(',').trim() || '',
    lead_source_id: leadSourceId,
    estimated_value: 0,
    notes: [
      `Source: LinkedIn`,
      `Profile: ${person.profileUrl || person.url || 'N/A'}`,
      `Headline: ${person.headline || person.title || 'N/A'}`,
      `Company: ${person.companyName || person.company || 'N/A'}`,
      `Keyword: ${webhookData.keyword}`,
      `Scraped: ${new Date().toISOString()}`
    ].join('\n')
  };
});

// Filter leads that have email (required for deduplication)
const validLeads = leads.filter(l => l.email && l.email.length > 0);

return [{ json: { leads: validLeads, source: 'linkedin' } }];

// Map Serper Google Maps results to GIMS Lead interface
const webhookData = $('Webhook Trigger').first().json;
const places = $input.first().json.places || [];
const leadSourceId = webhookData.lead_source_id || null;
const limit = webhookData.limit || 10;

const leads = places.slice(0, limit).map(place => {
  const nameParts = (place.title || 'Unknown').split(' ');
  const firstName = nameParts[0] || 'Unknown';
  const lastName = nameParts.slice(1).join(' ') || '';

  const addressParts = (place.address || '').split(',').map(s => s.trim());
  const city = addressParts.length >= 2 ? addressParts[addressParts.length - 2] : webhookData.city || '';
  const province = addressParts.length >= 3 ? addressParts[addressParts.length - 1] : '';

  // Build email from domain if available
  let email = '';
  if (place.website) {
    try {
      const domain = new URL(place.website).hostname.replace('www.', '');
      email = 'info@' + domain;
    } catch(e) { /* no valid URL */ }
  }

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: place.title || '',
    email: email,
    phone: place.phoneNumber || place.phone || '',
    job_title: place.category || '',
    address: place.address || '',
    city: city,
    province: province,
    lead_source_id: leadSourceId,
    estimated_value: 0,
    notes: [
      `Source: Google Maps`,
      `Rating: ${place.rating || 'N/A'} (${place.ratingCount || 0} reviews)`,
      `Category: ${place.category || 'N/A'}`,
      `Website: ${place.website || 'N/A'}`,
      `CID: ${place.cid || 'N/A'}`,
      `Keyword: ${webhookData.keyword}`,
      `Scraped: ${new Date().toISOString()}`
    ].join('\n')
  };
});

// Filter leads that have email (required for deduplication)
const validLeads = leads.filter(l => l.email && l.email.length > 0);

return [{ json: { leads: validLeads, source: 'google_maps' } }];
